    def check_artist_availability(self, artist_id: int, event_date: str) -> bool:
        """Check artist availability on date"""
        conn = None
        cursor = None
        try:
            conn = self.db_manager.get_connection()
            cursor = conn.cursor()
            
            query = """
                SELECT COUNT(*) as conflict_count
                FROM event_list
                WHERE artist = %s 
                AND start_date = %s
                AND status = 1
                AND event_status NOT IN ('Cancelled', 'Rejected')
            """
            
            cursor.execute(query, (artist_id, event_date))
            result = cursor.fetchone()
            
            return result[0] == 0
            
        except mysql.connector.Error as e:
            logger.error(f"Database error in check_artist_availability: {e}")
            return True  # Default to available if check fails
        finally:
            if cursor:
                cursor.close()
            if conn:
                conn.close()
    
